export const APP_VERSION = '1.5.0';

export enum AppStatus {
  IDLE = 'IDLE',
  GENERATING = 'GENERATING',
  ANALYZING = 'ANALYZING',
  PLAYING = 'PLAYING',
  ERROR = 'ERROR',
}

export interface AudioState {
  isPlaying: boolean;
  currentTime: number;
  duration: number;
}

export type AnalysisStyle = 'news' | 'podcast' | 'deep' | 'quick';

export type RewriteStyle = 'normal' | 'podcast' | 'simple' | 'intimate' | 'romantic';

export interface SourceLink {
  title: string;
  url: string;
}

export interface CredibilityData {
  score: number; // 0-100
  level: 'low' | 'doubtful' | 'trustworthy' | 'verified';
  label: string;
}

export interface HistoryItem {
  id: string;
  text: string;
  timestamp: number;
  sourceType: 'url' | 'text' | 'topic';
  meta?: {
    url?: string;
    topicId?: string;
    topicLabel?: string;
    analysisStyle?: AnalysisStyle;
    sources?: SourceLink[];
    credibility?: CredibilityData;
    questions?: string[];
    title?: string;
    chatMessages?: ChatMessage[];
  };
}

export interface VoiceOption {
  id: string;
  name: string;
  gender: 'male' | 'female';
  description: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
  isPlaying?: boolean;
  sources?: SourceLink[];
  credibility?: CredibilityData;
}

export interface AnalysisResult {
  text: string;
  questions: string[];
  sources: SourceLink[];
  credibility?: CredibilityData;
}

export interface QAResponse {
  answer: string;
  nextQuestions: string[];
  sources: SourceLink[];
  credibility?: CredibilityData;
}

