    </div>
);

// Helper to format time MM:SS
const formatTime = (time: number) => {
    if (!isFinite(time)) return '00:00';
    const minutes = Math.floor(time / 60);
    const seconds = Math.floor(time % 60);
    return `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
};

export const TextToSpeech: React.FC<TextToSpeechProps> = ({ onStatusChange, showHistory, setShowHistory }) => {
  // --- STATE ---
  const [viewMode, setViewMode] = useState<'INPUT' | 'CHAT'>('INPUT');
  const [inputType, setInputType] = useState<'TOPIC' | 'URL' | 'TEXT'>('TOPIC'); 

  // Content
  const [text, setText] = useState<string>('');
  const [newsUrl, setNewsUrl] = useState<string>('');
  const [selectedTopic, setSelectedTopic] = useState<string>('ai_ml');
  const [customTopic, setCustomTopic] = useState<string>('');
  const [sources, setSources] = useState<SourceLink[]>([]);
  const [credibility, setCredibility] = useState<CredibilityData | null>(null);

  // Settings
  const [analysisStyle, setAnalysisStyle] = useState<AnalysisStyle>('podcast');
  const [selectedVoice, setSelectedVoice] = useState<string>('Kore');
  const [rewriteStyle, setRewriteStyle] = useState<RewriteStyle>('normal');
  const [openDropdown, setOpenDropdown] = useState<'VOICE' | 'STYLE' | null>(null);

  // History State
  const [history, setHistory] = useState<HistoryItem[]>([]);

  // Logic
  const [status, setStatus] = useState<AppStatus>(AppStatus.IDLE);
  const [generatingId, setGeneratingId] = useState<string | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [currentTime, setCurrentTime] = useState<number>(0);
  const [duration, setDuration] = useState<number>(0);
  const [playbackRate, setPlaybackRate] = useState<number>(1);
  const [showLongWaitMessage, setShowLongWaitMessage] = useState<boolean>(false);
  const [isPlayerMinimized, setIsPlayerMinimized] = useState<boolean>(false);
  const [isCopied, setIsCopied] = useState<boolean>(false);

  // Chat
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([]);
  const [suggestedQuestions, setSuggestedQuestions] = useState<string[]>([]);
  const [chatInput, setChatInput] = useState<string>('');

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const chatEndRef = useRef<HTMLDivElement>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const dropdownRef = useRef<HTMLDivElement>(null);
  const historyRef = useRef<HTMLDivElement>(null);

  // Audio Caching for Zero Latency
  const audioCache = useRef<Map<string, string>>(new Map());
  const activeRequests = useRef<Map<string, Promise<string>>>(new Map());

  // --- EFFECTS ---
  useEffect(() => {
    onStatusChange?.(status);
  }, [status, onStatusChange]);

  // Load History from LocalStorage
  useEffect(() => {
      const saved = localStorage.getItem('zendia_history');
      if (saved) {
          try {
              setHistory(JSON.parse(saved));
          } catch (e) {
              console.error("Failed to load history", e);
          }
      }
  }, []);

  // Save History to LocalStorage on change
  useEffect(() => {
      localStorage.setItem('zendia_history', JSON.stringify(history));
  }, [history]);

  useEffect(() => {
    const audio = new Audio();
    audioRef.current = audio;

    const onTimeUpdate = () => setCurrentTime(audio.currentTime);
    const onLoadedMetadata = () => { if (isFinite(audio.duration)) setDuration(audio.duration); };
    const onPlay = () => setStatus(AppStatus.PLAYING);
    const onPause = () => setStatus(prev => (prev === AppStatus.PLAYING ? AppStatus.IDLE : prev));
    const onEnded = () => { setStatus(AppStatus.IDLE); };

    audio.addEventListener('timeupdate', onTimeUpdate);
    audio.addEventListener('loadedmetadata', onLoadedMetadata);
    audio.addEventListener('play', onPlay);
    audio.addEventListener('pause', onPause);
    audio.addEventListener('ended', onEnded);

    return () => {
      audio.pause();
      audioRef.current = null;
    };
  }, []);

  useEffect(() => {
    if (audioRef.current) {
        audioRef.current.playbackRate = playbackRate;
    }
  }, [playbackRate]);

  useEffect(() => {
    if (viewMode === 'CHAT') {
        if (scrollContainerRef.current) {
            scrollContainerRef.current.scrollTop = 0;
        }
    }
  }, [viewMode]);

  useEffect(() => {
    if (viewMode === 'CHAT' && chatMessages.length > 0) {
        chatEndRef.current?.scrollIntoView({ behavior: 'smooth' });
    }
  }, [chatMessages, viewMode]);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setOpenDropdown(null);
      }
      if (historyRef.current && !historyRef.current.contains(event.target as Node)) {
          setShowHistory(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  useEffect(() => {
    if (text && viewMode === 'CHAT') {
        prefetchAudio(text, selectedVoice);
    }
  }, [text, selectedVoice, viewMode]);

  // --- HELPERS ---
  const getVoiceLabel = (id: string) => VOICES.find(v => v.id === id)?.name || id;
  const getStyleLabel = (style: AnalysisStyle) => STYLES.find(s => s.id === style)?.label || style;

  const getCredibilityVisuals = (data: CredibilityData | null | undefined) => {
    if (!data) return { color: 'text-slate-500', bg: 'bg-slate-800/60', border: 'border-slate-800/60', icon: '?', shadow: '' };
    switch(data.level) {
        case 'low': return { 
            color: 'text-rose-500', 
            bg: 'bg-rose-950/20', 
            border: 'border-rose-500/40', 
            icon: '!', 
            shadow: 'shadow-[0_0_15px_rgba(244,63,94,0.1)]' 
        };
        case 'doubtful': return { 
            color: 'text-amber-500', 
            bg: 'bg-amber-950/20', 
            border: 'border-amber-500/40', 
            icon: '?', 
            shadow: 'shadow-[0_0_15px_rgba(245,158,11,0.1)]' 
        };
        case 'trustworthy': 
        case 'verified': return { 
            color: 'text-emerald-400', 
            bg: 'bg-emerald-950/20', 
            border: 'border-emerald-400/40', 
            icon: '✓', 
            shadow: 'shadow-[0_0_15px_rgba(16,185,129,0.1)]' 
        };
        default: return { 
            color: 'text-slate-400', 
            bg: 'bg-slate-950/20', 
            border: 'border-slate-600', 
            icon: '-', 
            shadow: '' 
        };
    }
  };

  const mainCredVis = getCredibilityVisuals(credibility);

  const saveToHistory = (
      resultText: string, 
      resultSources: SourceLink[], 
      resultCred: CredibilityData | undefined, 
      resultQs: string[]
  ) => {
      const newItem: HistoryItem = {
          id: Date.now().toString(),
          text: resultText,
          timestamp: Date.now(),
          sourceType: inputType === 'TOPIC' ? 'topic' : (inputType === 'URL' ? 'url' : 'text'),
          meta: {
              url: newsUrl,
              topicId: selectedTopic,
              topicLabel: customTopic || TOPICS.find(t => t.id === selectedTopic)?.label,
              analysisStyle: analysisStyle,
              sources: resultSources,
              credibility: resultCred,
              questions: resultQs,
              chatMessages: []
          }
      };
      setHistory(prev => [newItem, ...prev].slice(0, 50)); // Keep last 50
  };

  const updateHistoryChat = (newMessages: ChatMessage[]) => {
      setHistory(prev => {
          if (prev.length === 0) return prev;
          const head = prev[0];
          if (head.text === text) {
              return [{
                  ...head,
                  meta: { ...head.meta, chatMessages: newMessages }
              }, ...prev.slice(1)];
          }
          return prev;
      });
  };

  const restoreHistoryItem = (item: HistoryItem) => {
      setText(item.text);
      if (item.meta) {
          setSources(item.meta.sources || []);
          setCredibility(item.meta.credibility || null);
          setSuggestedQuestions(item.meta.questions || []);
          setChatMessages(item.meta.chatMessages || []);
          setAnalysisStyle(item.meta.analysisStyle || 'podcast');

          if (item.sourceType === 'url' && item.meta.url) {
              setInputType('URL');
              setNewsUrl(item.meta.url);
          } else if (item.sourceType === 'topic') {
              setInputType('TOPIC');
              if (item.meta.topicId) setSelectedTopic(item.meta.topicId);
              if (item.meta.topicLabel && !TOPICS.find(t => t.id === item.meta.topicId)) {
                   setCustomTopic(item.meta.topicLabel);
              }
          } else {
              setInputType('TEXT');
          }
      }

      setViewMode('CHAT');
      setShowHistory(false);
      setAudioUrl(null);
      prefetchAudio(item.text, selectedVoice);
  };

  const deleteHistoryItem = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();
      setHistory(prev => prev.filter(i => i.id !== id));
  };

  const clearAllHistory = () => {
      if (history.length === 0) return;
      if (window.confirm('آیا مطمئن هستید که می‌خواهید تمام تاریخچه تحلیل‌ها را پاک کنید؟')) {
          setHistory([]);
      }
  };

  // --- AUDIO LOGIC ---
  const prefetchAudio = async (textToFetch: string, voiceId: string) => {
      if (!textToFetch) return;
      const key = `${textToFetch.substring(0, 30)}_${textToFetch.length}_${voiceId}`;

      if (audioCache.current.has(key) || activeRequests.current.has(key)) return;

      const promise = generatePersianSpeech(textToFetch, voiceId)
        .then(base64 => {
             const audioBytes = decode(base64);
             const wavBlob = createWavBlob(audioBytes, 24000);
             const url = URL.createObjectURL(wavBlob);
             audioCache.current.set(key, url);
             return url;
        })
        .catch(err => {
             console.warn("Prefetch background error:", err);
             return "";
        })
        .finally(() => {
             activeRequests.current.delete(key);
        });

      activeRequests.current.set(key, promise);
  };

  const handleMainAction = async () => {
    if (status === AppStatus.GENERATING || status === AppStatus.ANALYZING) return;

    if (status === AppStatus.PLAYING) {
        audioRef.current?.pause();
        return;
    }

    try {
      setStatus((inputType === 'URL' || inputType === 'TOPIC' || (inputType === 'TEXT' && rewriteStyle !== 'normal')) ? AppStatus.ANALYZING : AppStatus.GENERATING);
      setAudioUrl(null); 
      setSources([]);
      setCredibility(null);
      setChatMessages([]);
      setIsPlayerMinimized(false);

      let resultText = text;
      let resultQs: string[] = [];
      let resultSources: SourceLink[] = [];
      let resultCred: CredibilityData | undefined = undefined;

      if (inputType === 'TOPIC') {
          let result;
          if (customTopic && customTopic.trim().length > 0) {
              result = await analyzeNewsFromTopic('custom_search', customTopic, analysisStyle);
          } else {
              const topic = TOPICS.find(t => t.id === selectedTopic);
              if (!topic) return;
              result = await analyzeNewsFromTopic(topic.id, topic.label, analysisStyle);
          }

          setText(result.text);
          setSuggestedQuestions(result.questions);
          setSources(result.sources);
          if (result.credibility) setCredibility(result.credibility);

          resultText = result.text;
          resultQs = result.questions;
          resultSources = result.sources;
          resultCred = result.credibility;

      } else if (inputType === 'URL') {
        if (!newsUrl) return;
        const result = await analyzeNewsFromUrl(newsUrl, analysisStyle);
        setText(result.text);
        setSuggestedQuestions(result.questions);
        setSources(result.sources);
        if (result.credibility) setCredibility(result.credibility);

        resultText = result.text;
        resultQs = result.questions;
        resultSources = result.sources;
        resultCred = result.credibility;
      } else if (inputType === 'TEXT' && rewriteStyle !== 'normal') {
          // New Rewrite Logic
          if (!text.trim()) return;
          const rewritten = await rewriteText(text, rewriteStyle);
          setText(rewritten);
          resultText = rewritten;
      }

      if (!resultText) return;

      // Save to History
      saveToHistory(resultText, resultSources, resultCred, resultQs);

      prefetchAudio(resultText, selectedVoice);

      setNewsUrl('');
      setCustomTopic('');

      setViewMode('CHAT');
      setStatus(AppStatus.IDLE);

    } catch (err) {
      console.error(err);
      setStatus(AppStatus.ERROR);
      setTimeout(() => setStatus(AppStatus.IDLE), 3000);
    }
  };

  const handleInputKeyDown = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
        e.currentTarget.blur();
        handleMainAction();
    }
  };

  const handleBackToInput = () => {
    setViewMode('INPUT');
    setNewsUrl('');
    setCustomTopic('');
    setSelectedTopic('ai_ml'); 
    setChatMessages([]); 
    setSources([]); 
    setCredibility(null); 
    setSuggestedQuestions([]); 
  };

  const handlePlayText = async (textToPlay: string, id: string) => {
      if (generatingId) return;
      const key = `${textToPlay.substring(0, 30)}_${textToPlay.length}_${selectedVoice}`;

      setShowLongWaitMessage(false);
      setIsPlayerMinimized(false);

      const waitTimer = setTimeout(() => {
          setShowLongWaitMessage(true);
      }, 5000);

      try {
          setGeneratingId(id);

          let url = audioCache.current.get(key);

          if (!url) {
              const pending = activeRequests.current.get(key);
              if (pending) {
                  setStatus(AppStatus.GENERATING); 
                  url = await pending;
              } else {
                  setStatus(AppStatus.GENERATING);
                  const base64Audio = await generatePersianSpeech(textToPlay, selectedVoice);
                  const audioBytes = decode(base64Audio);
                  const wavBlob = createWavBlob(audioBytes, 24000);
                  url = URL.createObjectURL(wavBlob);
                  audioCache.current.set(key, url);
              }
          }

          clearTimeout(waitTimer);
          setShowLongWaitMessage(false);

          if (url) {
            setAudioUrl(url);
            if (audioRef.current) {
                audioRef.current.src = url;
                audioRef.current.playbackRate = playbackRate;
                setStatus(AppStatus.PLAYING);
                try {
                    await audioRef.current.play();
                } catch (playErr) {
                    console.error("Autoplay prevented:", playErr);
                    setStatus(AppStatus.IDLE);
                }
            }
          } else {
            throw new Error("Could not generate audio URL");
          }

      } catch (e) {
          console.error(e);
          setStatus(AppStatus.ERROR);
          setTimeout(() => setStatus(AppStatus.IDLE), 2000);
      } finally {
          clearTimeout(waitTimer);
          setShowLongWaitMessage(false);
          setGeneratingId(null);
      }
  };

  const togglePlayPause = () => {
    if (audioRef.current && audioUrl) {
      if (status === AppStatus.PLAYING) audioRef.current.pause();
      else audioRef.current.play();
    }
  };

  const handleClosePlayer = () => {
    if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current.currentTime = 0;
    }
    setAudioUrl(null);
    setStatus(AppStatus.IDLE);
    setGeneratingId(null);
    setIsPlayerMinimized(false);
  };

  const toggleMinimize = () => {
      setIsPlayerMinimized(!isPlayerMinimized);
  };

  const cycleSpeed = () => {
      const idx = SPEEDS.indexOf(playbackRate);
      const nextIdx = (idx + 1) % SPEEDS.length;
      setPlaybackRate(SPEEDS[nextIdx]);
  };

  const handleDownload = () => {
      if (audioUrl) {
          const a = document.createElement('a');
          a.href = audioUrl;
          a.download = `zendia-audio-${Date.now()}.wav`;
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);
      }
  };

  const handleShare = async () => {
      if (!text) return;
      let shareContent = text;
      if (sources.length > 0) {
          shareContent += "\n\nمنابع:\n" + sources.map(s => `• ${s.title}: ${s.url}`).join('\n');
      }
      shareContent += "\n\nShared via Zendia";

      try {
          await navigator.clipboard.writeText(shareContent);
          setIsCopied(true);
          setTimeout(() => setIsCopied(false), 2000);
      } catch (err) {
          console.error("Failed to copy", err);
      }
  };

  const handleSendMessage = async (msgText: string = chatInput) => {
    if (!msgText.trim()) return;
    const userMsg: ChatMessage = { id: Date.now().toString(), role: 'user', text: msgText, timestamp: Date.now() };
    const newChatState = [...chatMessages, userMsg];
    setChatMessages(newChatState);
    setChatInput('');
    setStatus(AppStatus.ANALYZING);

    // Optimistic update of history
    updateHistoryChat(newChatState);

    try {
      const result = await askQuestionAboutContent(text, msgText, newChatState);
      const modelMsg: ChatMessage = { 
          id: (Date.now() + 1).toString(), 
          role: 'model', 
          text: result.answer, 
          timestamp: Date.now(),
          sources: result.sources,
          credibility: result.credibility
      };

      const updatedChatWithModel = [...newChatState, modelMsg];
      setChatMessages(updatedChatWithModel);
      setSuggestedQuestions(result.nextQuestions);

      updateHistoryChat(updatedChatWithModel);

      if (result.answer) {
          prefetchAudio(result.answer, selectedVoice);
      }

    } catch (e) {
      console.error(e);
    } finally {
        setStatus(AppStatus.IDLE);
    }
  };

  const isProcessing = status === AppStatus.GENERATING || status === AppStatus.ANALYZING || generatingId !== null;

  return (
