                    <div className="relative w-full">

                        {/* New Window Controls (Top Right Overlay) */}
                        <div className="absolute top-0 right-0 z-30 flex items-center p-2 gap-1 bg-gradient-to-l from-slate-950/80 to-transparent">
                            {/* Minimize */}
