                            </button>
                        </div>

                        {/* Progress & Visualizer */}
                        <div className="h-12 w-full relative group cursor-pointer" onClick={(e) => {
                             const rect = e.currentTarget.getBoundingClientRect();
                             const pos = (e.clientX - rect.left) / rect.width;
                             if(audioRef.current && isFinite(duration)) audioRef.current.currentTime = pos * duration;
                        }}>
                            <div className="absolute inset-0 opacity-30">
                                <AudioVisualizer isPlaying={status === AppStatus.PLAYING} />
                            </div>

                            {/* Progress Bar Overlay */}
                            <div className="absolute bottom-0 left-0 h-1 bg-primary-500 transition-all duration-200" style={{ width: `${(currentTime / (duration || 1)) * 100}%` }}></div>
