                        </div>

                        {/* Time Row (Moved out of visualizer for visibility) */}
                        <div className="flex justify-between px-4 pt-2 -mt-1">
                            <span className="text-xs font-mono font-bold text-cyan-300 drop-shadow-[0_0_5px_rgba(34,211,238,0.5)]">
                                {formatTime(currentTime)}
                            </span>
                            <span className="text-xs font-mono font-bold text-slate-400">
                                {formatTime(duration)}
                            </span>
                        </div>

                        {/* Controls */}
                        <div className="flex items-center justify-between px-6 py-4 pt-1">

                            {/* Left: Extra Controls */}
                            <div className="flex items-center gap-3">
                                 {/* Download */}
                                 <button onClick={handleDownload} className="text-slate-500 hover:text-primary-400 transition-colors" title="دانلود">
                                    <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                                 </button>
                                 {/* Speed */}
                                 <button onClick={cycleSpeed} className="w-8 text-xs font-mono font-bold text-slate-500 hover:text-primary-400 transition-colors">
                                    {playbackRate}x
                                 </button>
                            </div>

                            {/* Center: Play/Pause */}
                            <button 
                                onClick={togglePlayPause}
                                className="w-14 h-14 bg-primary-500 rounded-full flex items-center justify-center text-slate-900 shadow-[0_0_20px_rgba(34,211,238,0.4)] hover:scale-105 transition-transform"
                            >
                                {status === AppStatus.PLAYING ? (
                                     <svg className="w-7 h-7" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M10 9v6m4-6v6" /></svg>
                                ) : (
                                     <svg className="w-7 h-7 ml-1" viewBox="0 0 24 24" fill="currentColor"><path fillRule="evenodd" d="M4.5 5.653c0-1.426 1.529-2.33 2.779-1.643l11.54 6.348c1.295.712 1.295 2.573 0 3.285L7.28 19.991c-1.25.687-2.779-.217-2.779-1.643V5.653z" clipRule="evenodd" /></svg>
                                )}
                            </button>

                            {/* Right: Switch View */}
                            <button 
                                onClick={() => {
                                    if (viewMode === 'INPUT') {
                                        setViewMode('CHAT');
                                    } else {
                                        handleBackToInput();
                                    }
                                }}
                                className={`p-2 rounded-xl border transition-all ${viewMode === 'CHAT' ? 'bg-slate-900 border-primary-500 text-primary-400' : 'border-transparent text-slate-500 hover:text-white'}`}
                                title={viewMode === 'INPUT' ? "نمایش تحلیل" : "بازگشت به ورودی"}
                            >
                                 {viewMode === 'INPUT' ? (
                                     <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg>
                                 ) : (
                                     <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M11 17l-5-5m0 0l5-5m-5 5h12" /></svg>
                                 )}
                            </button>
                        </div>
                    </div>
                )}
            </div>
        )}

        {/* LONG WAIT TOAST */}
        {showLongWaitMessage && (status === AppStatus.GENERATING) && (
            <div className="fixed bottom-24 left-1/2 -translate-x-1/2 bg-amber-500/90 text-slate-900 px-4 py-2 rounded-full shadow-lg z-[60] animate-in fade-in slide-in-from-bottom-2 duration-300 flex items-center gap-2 backdrop-blur-sm">
                <svg className="w-4 h-4 animate-spin" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                <span className="text-xs font-bold">در حال آماده‌سازی پادکست، صبور باشید...</span>
            </div>
        )}

    </div>
  );
};

