         <circle cx="12" cy="12" r="8" strokeWidth={1.5} />
         <circle cx="12" cy="12" r="2" fill="currentColor" />
         <g className="reel-spin">
            <path strokeLinecap="round" strokeWidth={1.5} d="M12 12L12 4M12 12L19 16M12 12L5 16" />
         </g>
       </svg>
