         <style>{`
            .clapper-arm { transform-origin: 2px 11px; animation: clapAction 2s infinite; }
            @keyframes clapAction { 0%, 10% { transform: rotate(0deg); } 15% { transform: rotate(-20deg); } 20% { transform: rotate(0deg); } 100% { transform: rotate(0deg); } }
