            className={`absolute inset-y-0 right-0 w-64 bg-slate-950/95 backdrop-blur-xl border-l border-slate-800 z-50 transition-transform duration-300 ease-out shadow-2xl ${showHistory ? 'translate-x-0' : 'translate-x-full'}`}
