                                            onClick={() => setRewriteStyle(style.id)}
                                            className={`px-2 py-1 rounded-md text-[9px] font-bold transition-all ${rewriteStyle === style.id ? 'bg-primary-500 text-slate-950 shadow-sm' : 'text-slate-500 hover:text-slate-300'}`}
                                        >
                                            {style.label}
                                        </button>
                                    ))}
                                </div>
                            </div>

