                                            {msg.sources.map((src, idx) => (
                                                <a 
                                                    key={idx} 
                                                    href={src.url} 
                                                    target="_blank" 
                                                    rel="noreferrer"
                                                    className="inline-flex items-center gap-1 px-1.5 py-0.5 bg-black/20 hover:bg-black/40 rounded text-[9px] text-slate-400 hover:text-primary-300 transition-colors"
