                        <div className="h-12 w-full relative group cursor-pointer" onClick={(e) => {
                             const rect = e.currentTarget.getBoundingClientRect();
                             const pos = (e.clientX - rect.left) / rect.width;
                             if(audioRef.current && isFinite(duration)) audioRef.current.currentTime = pos * duration;
