                                     <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                                 </button>
                             </div>
                         </div>
                     ))}
             </div>
        </div>

        {/* CENTER CONTENT AREA */}
        <div className="flex-1 relative overflow-hidden flex flex-col w-full">
            <div className={`absolute inset-0 px-6 py-4 transition-all duration-500 ease-out transform ${viewMode === 'INPUT' ? 'opacity-100 translate-x-0 z-20' : 'opacity-0 translate-x-10 -z-10 pointer-events-none'}`}>
                 <div className="h-full flex flex-col pt-1 gap-1 items-center overflow-y-auto no-scrollbar pb-0">
                     {inputType === 'TOPIC' && (
                         <div className="w-full flex flex-col items-center gap-0">
