                                    {!customTopic && <div className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-600 pointer-events-none"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg></div>}
                                </div>
                                {TOPICS.map((topic) => (
                                    <button key={topic.id} onClick={() => { setSelectedTopic(topic.id); setCustomTopic(''); }} className={`relative group rounded-xl border p-2 flex flex-col items-center gap-1 transition-all duration-300 ${selectedTopic === topic.id ? 'scale-[1.02] bg-slate-800/80 border-primary-500 shadow-[0_0_15px_rgba(34,211,238,0.3)] ring-1 ring-primary-500/50' : 'bg-slate-900/40 border-slate-800 hover:border-slate-600 active:scale-95'}`} style={{ minHeight: '60px' }}>
                                        <div className={`p-1.5 rounded-full transition-colors ${selectedTopic === topic.id ? 'bg-primary-500/20 text-primary-400' : 'bg-slate-800 text-slate-500 group-hover:text-slate-300'}`}>{topic.icon}</div>
                                        <span className={`text-[11px] font-bold ${selectedTopic === topic.id ? 'text-white' : 'text-slate-400'}`}>{topic.label}</span>
                                        {(topic.id === 'cinema_iran' || topic.id === 'music_iran') ? <span className="absolute top-2 right-2 w-1.5 h-1.5 rounded-full bg-emerald-500 shadow-[0_0_5px_#10b981]" title="منابع داخلی"></span> : <span className="absolute top-2 right-2 w-1.5 h-1.5 rounded-full bg-blue-500 shadow-[0_0_5px_#3b82f6]" title="منابع جهانی"></span>}
                                    </button>
