                             </div>
                             <input value={newsUrl} onChange={(e) => setNewsUrl(e.target.value)} onKeyDown={handleInputKeyDown} type="url" dir="ltr" placeholder="https://website.com/news/..." className="w-full bg-slate-900 border border-slate-700 rounded-xl p-4 text-center text-sm text-primary-400 placeholder-slate-700 focus:border-primary-500 focus:shadow-[0_0_20px_rgba(34,211,238,0.1)] transition-all outline-none" />
                         </div>
