                        </svg>
                    </button>
                 </div>
            </div>

            <div className={`absolute inset-0 px-4 flex flex-col transition-all duration-500 ease-out transform ${viewMode === 'CHAT' ? 'opacity-100 translate-x-0 z-20' : 'opacity-0 -translate-x-10 -z-10 pointer-events-none'}`}>
                <div ref={scrollContainerRef} className="flex-1 overflow-y-auto no-scrollbar space-y-6 py-4 pb-4">
                    <div className={`bg-slate-900/40 border rounded-2xl p-4 pb-14 relative group transition-colors duration-500 ${mainCredVis.border} ${mainCredVis.shadow}`}>
                        <button onClick={handleBackToInput} className="absolute -top-3 left-4 px-3 py-1 rounded-full border border-slate-700 bg-slate-950 text-slate-400 hover:text-white hover:border-primary-500/50 hover:shadow-[0_0_10px_rgba(34,211,238,0.2)] transition-all flex items-center gap-1.5 text-[10px] font-bold shadow-lg z-10"><svg className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg><span>بازگشت</span></button>
