                             <button onClick={handleShare} className="w-8 h-8 rounded-full bg-slate-800/80 hover:bg-slate-700 text-slate-400 hover:text-white flex items-center justify-center transition-all border border-slate-700 shadow-sm" title="کپی متن و منابع">{isCopied ? <svg className="w-4 h-4 text-emerald-400" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg> : <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>}</button>
                             <button onClick={() => handlePlayText(text, 'main')} disabled={generatingId !== null} className="w-8 h-8 rounded-full bg-primary-500/20 hover:bg-primary-500 text-primary-400 hover:text-white flex items-center justify-center transition-all shadow-[0_0_10px_rgba(34,211,238,0.1)]">{generatingId === 'main' ? <span className="block w-2 h-2 bg-current rounded-full animate-bounce"></span> : <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z" /></svg>}</button>
                        </div>
                    </div>
                    {chatMessages.map(msg => { const msgCredVis = getCredibilityVisuals(msg.credibility); return (
                             <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                 <div className={`relative max-w-[90%] rounded-2xl px-4 py-3 text-sm shadow-sm ${msg.role === 'user' ? 'bg-primary-900/30 text-white border border-primary-500/20' : `bg-slate-900/60 text-slate-300 border ${msgCredVis.border || 'border-slate-700'}`}`}>
                                     {msg.role === 'model' && msg.credibility && <div className={`absolute -top-2 -right-1 px-2 py-0.5 rounded-full border bg-slate-950/80 ${msgCredVis.color} ${msgCredVis.border} flex items-center gap-1.5 text-[8px] font-bold`}><span>{msgCredVis.icon}</span></div>}
                                     <p className={msg.role === 'model' ? 'pb-2 text-xs leading-6' : ''}>{msg.text}</p>
                                     {msg.role === 'model' && msg.sources && msg.sources.length > 0 && <div className="mt-2 pt-2 border-t border-white/5 flex flex-wrap gap-1.5 pb-4">{msg.sources.map((src, idx) => <a key={idx} href={src.url} target="_blank" rel="noreferrer" className="inline-flex items-center gap-1 px-1.5 py-0.5 bg-black/20 hover:bg-black/40 rounded text-[9px] text-slate-400 hover:text-primary-300 transition-colors"><span className="w-1 h-1 rounded-full bg-slate-500"></span><span className="max-w-[80px] truncate">{src.title || new URL(src.url).hostname}</span></a>)}</div>}
                                     {msg.role === 'model' && <div className="absolute bottom-2 left-2"><button onClick={() => handlePlayText(msg.text, msg.id)} disabled={generatingId !== null} className="w-6 h-6 rounded-full bg-slate-700/50 hover:bg-primary-500 text-slate-400 hover:text-white flex items-center justify-center transition-all">{generatingId === msg.id ? <span className="block w-1.5 h-1.5 bg-current rounded-full animate-bounce"></span> : <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z" /></svg>}</button></div>}
                                 </div>
                             </div>
                         ); })}
                    <div ref={chatEndRef} />
                </div>
                <div className="flex-none pt-2 pb-2">
                     {suggestedQuestions.length > 0 && <div className="flex gap-2 overflow-x-auto pb-2 mb-2 no-scrollbar">{suggestedQuestions.map((q,i) => <button key={i} onClick={() => handleSendMessage(q)} className="whitespace-nowrap px-3 py-1 bg-slate-800/50 border border-slate-700 rounded-full text-[10px] text-slate-400 hover:text-primary-400 hover:border-primary-500 transition-colors backdrop-blur-sm">{q}</button>)}</div>}
