                                    <input type="text" value={customTopic} onChange={(e) => { setCustomTopic(e.target.value); if (e.target.value) setSelectedTopic(''); }} onKeyDown={handleInputKeyDown} placeholder="یک موضوع خبری یا یک خبر خاص را بنویسید" className={`w-full h-11 bg-slate-900/80 border ${customTopic ? 'border-primary-500 shadow-[0_0_15px_rgba(34,211,238,0.2)]' : 'border-slate-700'} rounded-xl px-4 text-xs text-center text-white placeholder-slate-500 focus:outline-none focus:border-primary-400 transition-all z-10 relative`} />
                                    {!customTopic && <div className="absolute right-3 top-1/2 -translate-y-1/2 text-slate-600 pointer-events-none"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg></div>}
