       <svg className="w-5 h-5" viewBox="0 0 24 24" fill="none" stroke="currentColor">
         <style>{`
           .reel-spin { animation: reelRotate 4s infinite linear; transform-origin: center; }
           @keyframes reelRotate { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
         `}</style>
         <circle cx="12" cy="12" r="8" strokeWidth={1.5} />
         <circle cx="12" cy="12" r="2" fill="currentColor" />
         <g className="reel-spin">
            <path strokeLinecap="round" strokeWidth={1.5} d="M12 12L12 4M12 12L19 16M12 12L5 16" />
