                                    ))}
                                </div>
                            </div>
                            <textarea value={text} onChange={(e) => setText(e.target.value)} placeholder="متن خود را اینجا بنویسید..." className="w-full h-56 bg-slate-900/50 rounded-2xl border border-slate-800 text-sm leading-relaxed text-slate-200 placeholder-slate-700 focus:ring-0 focus:border-primary-500/50 resize-none p-3 transition-all" />
                         </>
                     )}
                     {inputType === 'URL' && (
