                {isPlayerMinimized ? <div className="w-full h-full flex items-center justify-between px-4"><div className="flex items-center gap-3 flex-1"><button onClick={handleClosePlayer} className="text-slate-500 hover:text-rose-500 transition-colors p-1"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button><button onClick={togglePlayPause} className="w-7 h-7 rounded-full bg-primary-500/20 text-primary-400 flex items-center justify-center hover:bg-primary-500 hover:text-white transition-all">{status === AppStatus.PLAYING ? <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z" /></svg> : <svg className="w-3.5 h-3.5 ml-0.5" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z" /></svg>}</button><div className="flex-1 flex items-center gap-2"><div className="h-0.5 bg-slate-800 rounded-full flex-1 relative overflow-hidden"><div className="absolute top-0 left-0 h-full bg-primary-500" style={{ width: `${(currentTime / (duration || 1)) * 100}%` }}></div></div><span className="text-[8px] font-mono text-cyan-400 w-8 text-center">{formatTime(currentTime)}</span></div></div><button onClick={toggleMinimize} className="ml-4 text-slate-400 hover:text-primary-400 p-2"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" /></svg></button></div> : <div className="relative w-full">
                        <div className="absolute top-0 right-0 z-30 flex items-center p-1.5 gap-1 bg-gradient-to-l from-slate-950/80 to-transparent"><button onClick={toggleMinimize} className="p-1.5 rounded-lg text-slate-400 hover:text-primary-400 hover:bg-slate-800 transition-all" title="کوچک کردن"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg></button><button onClick={handleClosePlayer} className="p-1.5 rounded-lg text-slate-400 hover:text-rose-500 hover:bg-rose-950/30 transition-all" title="بستن"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button></div>
