        {audioUrl && (
            <div className={`flex-none bg-slate-950 border-t border-slate-800 z-50 transition-all duration-300 ease-in-out ${isPlayerMinimized ? 'h-12 overflow-hidden' : 'animate-in slide-in-from-bottom-full'}`}>
                {isPlayerMinimized ? <div className="w-full h-full flex items-center justify-between px-4"><div className="flex items-center gap-3 flex-1"><button onClick={handleClosePlayer} className="text-slate-500 hover:text-rose-500 transition-colors p-1"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button><button onClick={togglePlayPause} className="w-7 h-7 rounded-full bg-primary-500/20 text-primary-400 flex items-center justify-center hover:bg-primary-500 hover:text-white transition-all">{status === AppStatus.PLAYING ? <svg className="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 24 24"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z" /></svg> : <svg className="w-3.5 h-3.5 ml-0.5" fill="currentColor" viewBox="0 0 24 24"><path d="M8 5v14l11-7z" /></svg>}</button><div className="flex-1 flex items-center gap-2"><div className="h-0.5 bg-slate-800 rounded-full flex-1 relative overflow-hidden"><div className="absolute top-0 left-0 h-full bg-primary-500" style={{ width: `${(currentTime / (duration || 1)) * 100}%` }}></div></div><span className="text-[8px] font-mono text-cyan-400 w-8 text-center">{formatTime(currentTime)}</span></div></div><button onClick={toggleMinimize} className="ml-4 text-slate-400 hover:text-primary-400 p-2"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 15l7-7 7 7" /></svg></button></div> : <div className="relative w-full">
                        <div className="absolute top-0 right-0 z-30 flex items-center p-1.5 gap-1 bg-gradient-to-l from-slate-950/80 to-transparent"><button onClick={toggleMinimize} className="p-1.5 rounded-lg text-slate-400 hover:text-primary-400 hover:bg-slate-800 transition-all" title="کوچک کردن"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 9l-7 7-7-7" /></svg></button><button onClick={handleClosePlayer} className="p-1.5 rounded-lg text-slate-400 hover:text-rose-500 hover:bg-rose-950/30 transition-all" title="بستن"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg></button></div>
                        <div className="h-10 w-full relative group cursor-pointer" onClick={(e) => { const rect = e.currentTarget.getBoundingClientRect(); const pos = (e.clientX - rect.left) / rect.width; if(audioRef.current && isFinite(duration)) audioRef.current.currentTime = pos * duration; }}><div className="absolute inset-0 opacity-20"><AudioVisualizer isPlaying={status === AppStatus.PLAYING} /></div><div className="absolute bottom-0 left-0 h-1 bg-primary-500 transition-all duration-200" style={{ width: `${(currentTime / (duration || 1)) * 100}%` }}></div><div className="absolute bottom-0 w-full h-1 bg-slate-800 -z-10"></div></div>
                        <div className="flex justify-between px-4 pt-1.5 -mt-1"><span className="text-[10px] font-mono font-bold text-cyan-300 drop-shadow-[0_0_4px_rgba(34,211,238,0.5)]">{formatTime(currentTime)}</span><span className="text-[10px] font-mono font-bold text-slate-400">{formatTime(duration)}</span></div>
                        <div className="flex items-center justify-between px-6 py-2.5 pt-0.5"><div className="flex items-center gap-3"><button onClick={handleDownload} className="text-slate-500 hover:text-primary-400 transition-colors" title="دانلود"><svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg></button><button onClick={cycleSpeed} className="w-8 text-[10px] font-mono font-bold text-slate-500 hover:text-primary-400 transition-colors">{playbackRate}x</button></div><button onClick={togglePlayPause} className="w-12 h-12 bg-primary-500 rounded-full flex items-center justify-center text-slate-900 shadow-[0_0_15px_rgba(34,211,238,0.4)] hover:scale-105 transition-transform">{status === AppStatus.PLAYING ? <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2.5}><path strokeLinecap="round" strokeLinejoin="round" d="M10 9v6m4-6v6" /></svg> : <svg className="w-6 h-6 ml-0.5" viewBox="0 0 24 24" fill="currentColor"><path fillRule="evenodd" d="M4.5 5.653c0-1.426 1.529-2.33 2.779-1.643l11.54 6.348c1.295.712 1.295 2.573 0 3.285L7.28 19.991c-1.25.687-2.779-.217-2.779-1.643V5.653z" clipRule="evenodd" /></svg>}</button><button onClick={() => { if (viewMode === 'INPUT') setViewMode('CHAT'); else handleBackToInput(); }} className={`p-1.5 rounded-xl border transition-all ${viewMode === 'CHAT' ? 'bg-slate-900 border-primary-500 text-primary-400' : 'border-transparent text-slate-500 hover:text-white'}`} title={viewMode === 'INPUT' ? "نمایش تحلیل" : "بازگشت به ورودی"}>{viewMode === 'INPUT' ? <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" /></svg> : <svg className="w-5 h-5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M11 17l-5-5m0 0l5-5m-5 5h12" /></svg>}</button></div>
                    </div>}
            </div>
        )}
        {showLongWaitMessage && (status === AppStatus.GENERATING) && <div className="fixed bottom-20 left-1/2 -translate-x-1/2 bg-amber-500/90 text-slate-900 px-3 py-1.5 rounded-full shadow-lg z-[60] animate-in fade-in slide-in-from-bottom-2 duration-300 flex items-center gap-2 backdrop-blur-sm"><svg className="w-3 h-3 animate-spin" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg><span className="text-[10px] font-bold">در حال آماده‌سازی پادکست، صبور باشید...</span></div>}
    </div>
  );
};
